class FenwickTree {
    private size: number;
    private tree: number[];

    constructor(n: number) {
        this.size = n;
        this.tree = new Array(n + 1).fill(0);
    }

    update(index: number, delta: number): void {
        let i = index + 1;
        while (i <= this.size) {
            this.tree[i] += delta;
            i += (i & -i);
        }
    }

    prefixQuery(index: number): number {
        let sum = 0;
        let i = index + 1;
        while (i > 0) {
            sum += this.tree[i];
            i -= (i & -i);
        }
        return sum;
    }

    rangeQuery(left: number, right: number): number {
        if (left === 0) {
            return this.prefixQuery(right);
        }
        return this.prefixQuery(right) - this.prefixQuery(left - 1);
    }
}

function popcount(n: number): number {
    let cnt = 0;
    while (n) {
        cnt += n % 2;
        n = Math.floor(n / 2);
    }
    return cnt;
}

function solve(nums: number[], queries: number[][]): number[] {
    const depthTable = new Array(101).fill(0);
    for (let i = 1; i <= 100; i++) {
        if (i === 1) {
            depthTable[i] = 0;
        } else {
            depthTable[i] = 1 + depthTable[popcount(i)];
        }
    }

    function getDepth(x: number): number {
        if (x <= 100) {
            return depthTable[x];
        } else {
            const p = popcount(x);
            return 1 + depthTable[p];
        }
    }

    const n = nums.length;
    const trees: FenwickTree[] = Array(6);
    for (let i = 0; i <= 5; i++) {
        trees[i] = new FenwickTree(n);
    }

    const currentDepths: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
        const depthValue = getDepth(nums[i]);
        currentDepths[i] = depthValue;
        if (depthValue >= 0 && depthValue <= 5) {
            trees[depthValue].update(i, 1);
        }
    }

    const ans: number[] = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1], r = q[2], k = q[3];
            if (k <= 5 && k >= 0) {
                ans.push(trees[k].rangeQuery(l, r));
            } else {
                ans.push(0);
            }
        } else if (q[0] === 2) {
            const idx = q[1], val = q[2];
            const newDepth = getDepth(val);
            const oldDepth = currentDepths[idx];
            if (oldDepth !== newDepth) {
                if (oldDepth >= 0 && oldDepth <= 5) {
                    trees[oldDepth].update(idx, -1);
                }
                if (newDepth >= 0 && newDepth <= 5) {
                    trees[newDepth].update(idx, 1);
                }
                currentDepths[idx] = newDepth;
            }
        }
    }

    return ans;
}
