class Fenw {
    n: number;
    arr: number[];
    constructor(n: number) {
        this.n = n;
        this.arr = new Array(n+1).fill(0);
    }

    update(idx: number, delta: number): void {
        let i = idx + 1;
        while (i <= this.n) {
            this.arr[i] += delta;
            i += i & -i;
        }
    }

    query(idx: number): number {
        let sum = 0;
        let i = idx + 1;
        while (i > 0) {
            sum += this.arr[i];
            i -= i & -i;
        }
        return sum;
    }

    rangeQuery(l: number, r: number): number {
        if (l === 0) {
            return this.query(r);
        }
        return this.query(r) - this.query(l-1);
    }
}

function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const MAX_K = 5;
    const max_n = 60;

    function popcount(x: number): number {
        let s = x.toString(2);
        let cnt = 0;
        for (let char of s) {
            if (char === '1') cnt++;
        }
        return cnt;
    }

    let depSmall: number[] = new Array(max_n+1).fill(0);
    for (let i = 2; i <= max_n; i++) {
        let cnt = popcount(i);
        depSmall[i] = depSmall[cnt] + 1;
    }

    function depthOf(x: number): number {
        let cur = x;
        let steps = 0;
        while (cur > max_n) {
            cur = popcount(cur);
            steps++;
        }
        return steps + depSmall[cur];
    }

    let depthArr: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
        depthArr[i] = depthOf(nums[i]);
    }

    let BITs: Fenw[] = [];
    for (let k = 0; k <= MAX_K; k++) {
        BITs[k] = new Fenw(n);
    }

    for (let i = 0; i < n; i++) {
        let d = depthArr[i];
        if (d >= 0 && d <= MAX_K) {
            BITs[d].update(i, 1);
        }
    }

    let ans: number[] = [];
    for (let q of queries) {
        if (q[0] === 1) {
            let l = q[1];
            let r = q[2];
            let k = q[3];
            if (k < 0 || k > MAX_K) {
                ans.push(0);
            } else {
                ans.push(BITs[k].rangeQuery(l, r));
            }
        } else if (q[0] === 2) {
            let idx = q[1];
            let val = q[2];
            let oldDepth = depthArr[idx];
            let newDepth = depthOf(val);
            nums[idx] = val;
            depthArr[idx] = newDepth;
            if (oldDepth >= 0 && oldDepth <= MAX_K) {
                BITs[oldDepth].update(idx, -1);
            }
            if (newDepth >= 0 && newDepth <= MAX_K) {
                BITs[newDepth].update(idx, 1);
            }
        }
    }

    return ans;
}
