function solve(nums: number[], queries: number[][]): number[] {
    // Precompute popcount-depth for numbers up to 1e15, but since it's not feasible, compute on the fly with memoization
    const depthMap = new Map<number, number>();

    function getPopcount(x: number): number {
        let count = 0;
        while (x > 0) {
            count += x & 1;
            x >>>= 1;
        }
        return count;
    }

    function getDepth(x: number): number {
        if (x === 1) return 0;
        if (depthMap.has(x)) return depthMap.get(x)!;

        const next = getPopcount(x);
        const depth = 1 + getDepth(next);
        depthMap.set(x, depth);
        return depth;
    }

    // Precompute depths for all nums initially
    const depths: number[] = new Array(nums.length);
    for (let i = 0; i < nums.length; i++) {
        depths[i] = getDepth(nums[i]);
    }

    const answer: number[] = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const [_, l, r, k] = query;
            let count = 0;
            for (let i = l; i <= r; i++) {
                if (depths[i] === k) {
                    count++;
                }
            }
            answer.push(count);
        } else if (query[0] === 2) {
            const [_, idx, val] = query;
            nums[idx] = val;
            depths[idx] = getDepth(val);
        }
    }
    return answer;
}
